company_type,\\n    sip.pay_month,\\n    sip.insurance_type,\\n    sip.insurer_status,\\n    sip.pay_base\\nFROM \\n    social_insurance_payment sip\\nJOIN \\n    company_info ci ON sip.company_id = ci.company_id\\nWHERE \\n    sip.id_card = \'42090219700505000I\'\\n    AND sip.is_valid = \'1\'\\n    AND ci.is_valid = \'1\'\\n    AND ci.company_type IN (\'机关单位\', \'事业单位\')\\n    AND sip.insurer_status = \'101\'\\nORDER BY \\n    sip.pay_month DESC;\", \"result_raw\": [], \"result_summary\": \"数据库未返回任何记录。未能查证到当前事实。\", \"time_range\": null, \"supports_conclusion\": null, \"confidence\": 0.5, \"exec_status\": \"no_data\", \"created_at\": \"2026-03-25T00:10:13\"}, {\"evidence_id\": \"plan_calc_history_months\", \"rule_id\": \"CALC_HISTORY_MONTHS\", \"target_id_card\": \"42090219700505000I\", \"target\": \"申请人历史已领取月份与当前缴费月份是否满足精算核算需要？\", \"category\": \"CALC\", \"sql\": \"SQL 生成与执行链路遭受毁灭性破坏\", \"result_raw\": [], \"result_summary\": \"系统保护性拦截异常: Object of type Decimal is not JSON serializable\", \"time_range\": null, \"supports_conclusion\": null, \"confidence\": 0.0, \"exec_status\": \"failed\", \"created_at\": \"2026-03-25T00:10:39\"}]}','2026-03-24 16:11:41'),('6717ce9e-7c6f-4b79-9746-1d876551cd2a','42090219800101000A','POLICY_001','completed','/api/debate_stream','数据缺失','待定',1.0000,1,0,0,5,'2026-03-25 11:54:25','2026-03-25 11:56:04','{\"session_id\": \"6717ce9e-7c6f-4b79-9746-1d876551cd2a\", \"id_card\": \"42090219800101000A\", \"evidence_count\": 0, \"rounds_taken\": 0, \"final_conclusion\": \"数据缺失\", \"final_stance\": \"待定\", \"consensus_rate\": 1.0, \"is_consensus_reached\": true, \"history\": [{\"round_num\": 0, \"judgments\": [{\"agent_id\": \"agent_strict\", \"agent_role\": \"严格合规Agent\", \"debate_round\": 0, \"conclusion\": \"数据缺失\", \"stance\": \"待定\", \"confidence\": 0.0, \"evidence_refs\": [], \"reasoning\": \"系统错误导致判断失败: \'EvidencePlanItem\' object has no attribute \'question_id\'\", \"dissent_points\": [], \"key_finding\": \"系统调度异常\"}, {\"agent_id\": \"ag