ate, INTERVAL 60 YEAR)\\n                    WHEN gender = \'女\' THEN DATE_ADD(birth_date, INTERVAL 55 YEAR)\\n                END AS retirement_date_55_60,\\n                CASE\\n                    WHEN gender = \'女\' THEN DATE_ADD(birth_date, INTERVAL 50 YEAR)\\n                    ELSE NULL\\n                END AS retirement_date_50_female,\\n                TIMESTAMPDIFF(YEAR, birth_date, :system_date) AS current_age\\n            FROM person\\n            WHERE id_card = :id_card\", \"result_raw\": [{\"id_card\": \"42090219760310000D\", \"name\": \"赵争议\", \"gender\": \"男\", \"birth_date\": \"1976-03-10\", \"retirement_date_55_60\": \"2036-03-10\", \"retirement_date_50_female\": null, \"current_age\": 50}], \"result_summary\": \"当前年龄: 50 岁，估算退休时间（55/60岁标准）: 2036-03-10，女性50岁标准: N/A\", \"time_range\": null, \"supports_conclusion\": null, \"confidence\": 1.0, \"exec_status\": \"success\", \"created_at\": \"2026-03-24T15:35:35\"}, {\"evidence_id\": \"EXCL_008_000D\", \"rule_id\": \"EXCL_008\", \"target_id_card\": \"42090219760310000D\", \"target\": \"排斥检查：申领期间医保是否存在单位缴纳记录（310类型，101状态）\", \"category\": \"排斥条件\", \"sql\": \"SELECT pay_month, insurance_type, insurer_status,\\n                   pay_base, company_id\\n            FROM social_insurance_payment\\n            WHERE id_card = :id_card\\n              AND insurance_type = \'310\'\\n              AND insurer_status = \'101\'\\n              AND is_valid = \'1\'\\n            ORDER BY pay_month DESC\", \"result_raw\": [], \"result_summary\": \"查无数据（排斥检查：申领期间医保是否存在单位缴纳记录（310类型，101状态））\", \"time_range\": null, \"supports_conclusion\": true, \"confidence\": 1.0, \"exec_status\": \"no_data\", \"created_at\": \"2026-03-24T15:35:35\"}, {\"evidence_id\": \"EXCL_009_000D\", \"rule_id\": \"EXCL_009\", \"target_id_card\": \"42090219760310000D\", \"target\": \"排斥检查：是否缺失灵活就业养老社保缴费记录（110类型，102状态）\", \"category\": \"排斥条件\", \"sql\": \"SELECT pay_month, insurance_type, insurer_status, pay_base\\n            FROM social_i