                       WHEN gender = \'男\' THEN DATE_ADD(birth_date, INTERVAL 60 YEAR)\\n                        WHEN gender = \'女\' THEN DATE_ADD(birth_date, INTERVAL 55 YEAR)\\n                    END\\n                ) AS months_to_retirement,\\n                TIMESTAMPDIFF(MONTH, birth_date, :system_date) AS age_in_months\\n            FROM person\\n            WHERE id_card = :id_card\", \"result_raw\": [{\"id_card\": \"42090219760310000D\", \"name\": \"赵争议\", \"gender\": \"男\", \"birth_date\": \"1976-03-10\", \"estimated_retirement_date\": \"2036-03-10\", \"months_to_retirement\": 119, \"age_in_months\": 600}], \"result_summary\": \"出生日期: 1976-03-10，性别: 男，估算退休日期: 2036-03-10，距退休月数: 119 个月\", \"time_range\": null, \"supports_conclusion\": null, \"confidence\": 1.0, \"exec_status\": \"success\", \"created_at\": \"2026-03-24T15:35:35\"}, {\"evidence_id\": \"CALC_004_000D\", \"rule_id\": \"CALC_004\", \"target_id_card\": \"42090219760310000D\", \"target\": \"精算：本人灵活就业养老社保缴费月数统计（功能二情况4依据）\", \"category\": \"额度计算\", \"sql\": \"SELECT COUNT(DISTINCT pay_month) AS flex_pay_months,\\n                   MIN(pay_month) AS first_pay_month,\\n                   MAX(pay_month) AS last_pay_month\\n            FROM social_insurance_payment\\n            WHERE id_card = :id_card\\n              AND insurance_type = \'110\'\\n              AND insurer_status = \'102\'\\n              AND is_valid = \'1\'\", \"result_raw\": [{\"flex_pay_months\": 1, \"first_pay_month\": \"202602\", \"last_pay_month\": \"202602\"}], \"result_summary\": \"灵活就业社保缴费月数: 1 个月，首次缴费月: 202602，最近缴费月: 202602\", \"time_range\": null, \"supports_conclusion\": null, \"confidence\": 1.0, \"exec_status\": \"success\", \"created_at\": \"2026-03-24T15:35:35\"}, {\"evidence_id\": \"CALC_005_000D\", \"rule_id\": \"CALC_005\", \"target_id_card\": \"42090219760310000D\", \"target\": \"精算：困难认定类别（判断是否为高校毕业生，影响功能二情况3）\", \"category\": \"额度计算\", \"sql\": \"SELECT hardship_category, apply_date\\n            FROM hardship