INSERT INTO `rule_definitions` VALUES ('P001_EXCLUDE_001','POLICY_001','不能是企业法人','申请人不能是有效的企业法人','必须排除','SELECT COUNT(*) as cnt FROM company_info WHERE legal_person_id_card = :id_card AND is_valid \r\n  = \'1\'','排斥条件',1,'1','2026-03-25 10:45:27'),('P001_EXCLUDE_002','POLICY_001','不能是企业股东','申请人不能持有有效的企业股份','必须排除','SELECT COUNT(*) as cnt FROM company_shareholder WHERE id_card = :id_card AND is_valid =     \r\n  \'1\'','排斥条件',2,'1','2026-03-25 10:45:27'),('P001_EXCLUDE_003','POLICY_001','不能有单位缴费社保','近3个月不能有单位为其缴纳社保','必须排除','SELECT COUNT(*) as cnt FROM social_insurance_payment WHERE id_card = :id_card AND\r\n  insurer_status = \'101\' AND is_valid = \'1\' AND pay_month >= DATE_FORMAT(DATE_SUB(NOW(),   \r\n  INTERVAL 3 MONTH), \'%Y%m\')','排斥条件',3,'1','2026-03-25 10:45:27'),('P001_FLEX_001','POLICY_001','灵活就业社保缴费连续性','检查申请人灵活就业社保（insurer_st\r\n  atus=102）的缴费连续性，是否存在断缴。Agent需分析pay_month序列','灵活评判','SELECT pay_month, insurance_type, pay_base FROM social_insurance_payment WHERE id_card =    \r\n  :id_card AND insurer_status = \'102\' AND is_valid = \'1\' ORDER BY pay_month','基础资格',100,'1','2026-03-25 10:45:27'),('P001_FLEX_002','POLICY_001','困难类别是否符合政策范围','就业困难类别必须在政策允许范围内\r\n  （大龄失业人员、残疾人员等）。Agent需查询hardship_category并调用get_dict工具理解编码','灵活评判','SELECT hardship_category, apply_date, certify_org FROM hardship_certification WHERE id_card \r\n  = :id_card AND is_valid = \'1\'','基础资格',90,'1','2026-03-25 10:45:27'),('P001_FLEX_003','POLICY_001','是否存在身份切换风险','检查insurance_change_log中是否有即将发生的身份切换（从102到101），表示可能要去单位就业','灵活评判','SELECT event_date, old_status, new_status, related_company_id FROM insurance_change_log     \r\n  WHERE id_card = :id_card AND old_status = \'102\' AND new_status = \'101\' ORDER BY\r\n  event_date DESC','主动服务',110,'1','2026-03-25 10:45:27'),('P001_FLEX_004','POLICY_001','缴费基数波动分析','分析灵活就业期间缴费基数是否存在异常波动，大幅下降可能表示经营困难或数据异常','灵活评判','SELECT pay_month, pay_base, insurance_type FROM social_insurance_payment WHERE id_card =    \r\n  :id_card AND insurer_status = \'102\' AND is_valid = \'1\' ORDER BY pay_month','主动服务',120,'1','2026-03-25 10:45:27'),('P001_FLEX_005','POLICY_001','历史补贴领取情况','检查该人员历史上是否已领取过灵活就业社保补贴，分析剩余可领取月数','灵活评判','SELECT policy_code, apply_start_month, apply_end_month, grant_months, grant_amount FROM     \r\n  subsidy_payment_history WHERE id_card = :id_card AND is_valid = \'1\' ORDER BY grant_date    \r\n  DESC','额度计算',80,'1','2026-03-25 10:45:27'),('P001_MUST_001','POLICY_001','必须是生存状态','申请人生存状态必须为\"生存\"','必须满足','SELECT life_status FROM person WHERE id_card = :id_card','基础资格',5,'1','2026-03-25 10:45:27'),('P001_MUST_002','POLICY_001','必须有失业登记','申请人必须有有效的失业登记记录','必须满足','SELECT COUNT(*) as cnt FROM unemployment_registration WHERE id_card = :id_card AND is_valid \r\n  = \'1\'','基础资格',10,'1','2026-03-25 10:45:27'),('P001_MUST_003','POLICY_001','必须有困难认定','申请人必须有有效的就业困难人员认定','必须满足','SELECT COUNT(*) as cnt FROM hardship_certification WHERE id_card = :id_card AND is_valid =  \r\n  \'1\'','基础资格',15,'1','2026-03-25 10:45:27');
/*!40000 ALTER TABLE `rule_definitions` ENABLE KEYS */;
UNLOCK TABLES;

